// ============================================
// CONFIGURACIÓN CENTRAL - Edita los valores aquí
// ============================================
return [{
  json: {
    PUPPETEER_URL: 'https://workana-auto-pilot.ioefpm.easypanel.host',
    SUPABASE_URL: 'https://zcmqcosuvjndgcwylzna.supabase.co',
    SUPABASE_KEY: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InpjbXFjb3N1dmpuZGdjd3lsem5hIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzMxNTcwOCwiZXhwIjoyMDg4ODkxNzA4fQ.lgJ_VxIBAZMmTtjo3L4vUwsIGRD_glaYYsdhHkuUTHM',
    EVOLUTION_URL: 'https://evo.vortekai.es',
    EVOLUTION_INSTANCE: 'Ventas vortek',
    WHATSAPP_NUMBER: '34628706539',
    SEARCH_CATEGORIES: 'it-programming',
    SEARCH_PAGES: '2',
    MIN_RELEVANCE_AUTO: '80',
    MAX_PROPOSALS_DAY: '35',
    MAX_PROPOSALS_ON_PROJECT: '30',
    AUTO_MODE: false,
  }
}];

// Verificar horario activo (8:00-22:00 Europe/Madrid)
const now = new Date();
const madridTime = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Madrid' }));
const hour = madridTime.getHours();
const day = madridTime.getDay(); // 0=domingo

if (hour < 8 || hour >= 22 || day === 0) {
  // Fuera de horario - no ejecutar
  return [];
}

// Pasar la config adelante
return [{
  json: {
    ...$input.first().json,
    current_hour: hour,
    current_day: day,
    timestamp: now.toISOString()
  }
}];

// Extraer proyectos del resultado del scraping
const data = $input.first().json;

if (!data.success || !data.projects || data.projects.length === 0) {
  console.log('No se encontraron proyectos o error en scraping');
  return [];
}

// Devolver cada proyecto como item individual con config
return data.projects.map(project => ({
  json: {
    ...project,
    config: {
      PUPPETEER_URL: $('CONFIG').item.json.PUPPETEER_URL,
      SUPABASE_URL: $('CONFIG').item.json.SUPABASE_URL,
      SUPABASE_KEY: $('CONFIG').item.json.SUPABASE_KEY,
      EVOLUTION_URL: $('CONFIG').item.json.EVOLUTION_URL,
      EVOLUTION_INSTANCE: $('CONFIG').item.json.EVOLUTION_INSTANCE,
      WHATSAPP_NUMBER: $('CONFIG').item.json.WHATSAPP_NUMBER,
      AUTO_MODE: $('CONFIG').item.json.AUTO_MODE,
      MIN_RELEVANCE_AUTO: parseInt($('CONFIG').item.json.MIN_RELEVANCE_AUTO),
      MAX_PROPOSALS_ON_PROJECT: parseInt($('CONFIG').item.json.MAX_PROPOSALS_ON_PROJECT),
    }
  }
}));

// Filtrar proyectos nuevos - UNA sola consulta a Supabase para todos
const items = $input.all();

if (items.length === 0) return [];

const config = items[0].json.config;

// Obtener TODOS los URLs existentes de Supabase en una sola consulta
let existingUrls = new Set();
try {
  const resp = await fetch(
    `${config.SUPABASE_URL}/rest/v1/workana_projects?select=workana_url`,
    {
      headers: {
        'apikey': config.SUPABASE_KEY,
        'Authorization': `Bearer ${config.SUPABASE_KEY}`,
      }
    }
  );
  const existing = await resp.json();
  if (Array.isArray(existing)) {
    existingUrls = new Set(existing.map(r => r.workana_url));
  }
} catch (error) {
  console.error('Error consultando Supabase:', error.message);
  // Si falla, continuar con todos (mejor duplicar que perder)
}

// Filtrar solo proyectos nuevos
const newItems = items.filter(item => !existingUrls.has(item.json.url));

console.log(`Total: ${items.length}, Nuevos: ${newItems.length}, Ya existentes: ${items.length - newItems.length}`);

return newItems;

// Combinar datos del scraping con los detalles completos
const basic = $('Filtrar Nuevos').item.json;
const detailsResponse = $input.first().json;

if (!detailsResponse.success) {
  console.log(`Error obteniendo detalles: ${detailsResponse.error}`);
  return [{ json: { ...basic, details_error: true } }];
}

const details = detailsResponse.details;

// Extraer número de propuestas
const proposalsText = details.proposals || basic.proposals_text || '';
const proposalsMatch = proposalsText.match(/(\d+)/);
const proposalsCount = proposalsMatch ? parseInt(proposalsMatch[1]) : 0;

// Filtrar por número de propuestas
const maxProposals = basic.config.MAX_PROPOSALS_ON_PROJECT || 30;
if (proposalsCount > maxProposals) {
  console.log(`Demasiadas propuestas (${proposalsCount}): ${basic.title}`);
  return [];
}

return [{
  json: {
    ...basic,
    full_description: details.description || basic.description,
    full_title: details.title || basic.title,
    budget_detail: details.budget || basic.budget_text,
    category: details.category || basic.category || '',
    deadline: details.deadline || '',
    skills_detail: details.skills && details.skills.length > 0 ? details.skills : basic.skills,
    proposals_count: proposalsCount,
    client_name: details.client?.name || '',
    client_country: details.client?.country || '',
    client_rating: details.client?.rating || '',
    client_verified: details.client?.verified || false,
    publish_date: details.publish_date || basic.date_text || '',
    full_text: details.full_text || '',
  }
}];

// Parsear respuesta de la IA y estructurar datos
const aiResponse = $input.first().json;
const projectData = $('Combinar Datos').item.json;

// DEBUG: ver qué devuelve la IA
console.log('=== DEBUG IA RESPONSE ===');
console.log('Response keys:', Object.keys(aiResponse));
console.log('Has choices:', !!aiResponse.choices);
console.log('Has error:', !!aiResponse.error);

// Si OpenAI devolvió error
if (aiResponse.error) {
  console.error('OpenAI ERROR:', JSON.stringify(aiResponse.error));
  return [{
    json: {
      project: {
        workana_url: projectData.url,
        title: projectData.full_title || projectData.title,
        description: (projectData.full_description || projectData.description || '').substring(0, 2000),
        category: projectData.category || '',
        budget_text: projectData.budget_detail || projectData.budget_text || '',
        skills: projectData.skills_detail || projectData.skills || [],
        client_name: projectData.client_name || '',
        client_country: projectData.client_country || '',
        client_rating: parseFloat(projectData.client_rating) || null,
        client_verified: projectData.client_verified || false,
        proposals_count: projectData.proposals_count || 0,
        publication_date: projectData.publish_date || '',
        relevance_score: 50,
        red_flags: ['Error en IA: ' + (aiResponse.error?.message || 'desconocido')],
        status: 'error_ia',
      },
      proposal: {
        proposal_text: 'ERROR: La IA no pudo generar propuesta. Revisar credenciales OpenAI.',
        questions_text: '',
        budget_suggested: null,
        delivery_days: null,
        skills_recommended: [],
        portfolio_items: [],
        internal_notes: { error: JSON.stringify(aiResponse.error) },
      },
      config: projectData.config,
    }
  }];
}

let proposal;
try {
  const content = aiResponse.choices?.[0]?.message?.content;
  console.log('AI content (first 300 chars):', (content || 'NULL').substring(0, 300));

  if (!content) {
    console.error('NO CONTENT in AI response!');
    console.error('Full response (first 500):', JSON.stringify(aiResponse).substring(0, 500));
    return [];
  }
  proposal = JSON.parse(content);
} catch (e) {
  console.error('JSON PARSE ERROR:', e.message);
  return [];
}

console.log('AI verdict:', JSON.stringify({
  should_apply: proposal.should_apply,
  relevance: proposal.relevance_score,
  red_flags: proposal.red_flags,
}));

// Si la IA dice que no debemos aplicar, saltamos
if (!proposal.should_apply) {
  console.log('IA says NO APPLY:', projectData.title);
  return [];
}

return [{
  json: {
    project: {
      workana_url: projectData.url,
      title: projectData.full_title || projectData.title,
      description: (projectData.full_description || projectData.description || '').substring(0, 2000),
      category: projectData.category || '',
      budget_text: projectData.budget_detail || projectData.budget_text || '',
      skills: projectData.skills_detail || projectData.skills || [],
      client_name: projectData.client_name || '',
      client_country: projectData.client_country || '',
      client_rating: parseFloat(projectData.client_rating) || null,
      client_verified: projectData.client_verified || false,
      proposals_count: projectData.proposals_count || 0,
      publication_date: projectData.publish_date || '',
      relevance_score: proposal.relevance_score || 0,
      red_flags: proposal.red_flags || [],
      status: 'proposal_generated',
    },
    proposal: {
      proposal_text: proposal.proposal_text || '',
      questions_text: proposal.questions_text || '',
      budget_suggested: proposal.budget_suggested || null,
      delivery_days: proposal.delivery_days || null,
      skills_recommended: proposal.skills_recommended || [],
      portfolio_items: proposal.portfolio_items || [],
      internal_notes: proposal.internal_notes || {},
    },
    config: projectData.config,
  }
}];

// Obtener el ID del proyecto guardado para asociar la propuesta
const savedProject = $input.first().json;
const structuredData = $('Estructurar Datos').item.json;

const projectId = Array.isArray(savedProject)
  ? savedProject[0]?.id
  : savedProject?.id;

if (!projectId) {
  console.error('No se obtuvo ID del proyecto guardado');
  return [];
}

return [{
  json: {
    project_id: projectId,
    ...structuredData.proposal,
    project: structuredData.project,
    config: structuredData.config,
  }
}];

// Actualizar estado después del envío automático
const submitResult = $input.first().json;
const proposalData = $('Preparar Propuesta').item.json;

const success = submitResult.success === true;

return [{
  json: {
    id: proposalData.project_id,
    success,
    project_url: proposalData.project.workana_url,
    project_title: proposalData.project.title,
    proposal_text: proposalData.proposal_text,
    budget: proposalData.budget_suggested,
    relevance: proposalData.project.relevance_score,
    message: submitResult.message || (success ? 'Enviado' : 'Error'),
    auto_sent: true,
    config: proposalData.config,
    project_id: proposalData.project_id,
  }
}];

// Preparar notificación para modo manual (sin auto-submit)
const data = $('Preparar Propuesta').item.json;
const project = data.project;

return [{
  json: {
    auto_sent: false,
    success: false,
    project_url: project.workana_url,
    project_title: project.title,
    proposal_text: data.proposal_text,
    budget: data.budget_suggested,
    relevance: project.relevance_score,
    message: 'Pendiente de envío manual',
    config: data.config,
    project_id: data.project_id,
  }
}];

// Preparar mensaje de notificación WhatsApp
const data = $('Preparar Propuesta').item.json;
const project = data.project;
const isAuto = $input.first()?.json?.auto_sent || false;
const autoSuccess = $input.first()?.json?.success;

let statusEmoji, statusText;
if (isAuto && autoSuccess) {
  statusEmoji = '🤖✅';
  statusText = 'ENVIADO AUTOMÁTICAMENTE';
} else if (isAuto && !autoSuccess) {
  statusEmoji = '🤖❌';
  statusText = 'ERROR EN ENVÍO AUTO - Revisa manualmente';
} else {
  statusEmoji = '📋';
  statusText = 'PENDIENTE DE ENVÍO';
}

const relevanceBar = '█'.repeat(Math.floor(project.relevance_score / 10)) + '░'.repeat(10 - Math.floor(project.relevance_score / 10));

const msg = `${statusEmoji} *${statusText}*

🎯 *${project.title}*
Relevancia: ${relevanceBar} ${project.relevance_score}/100

💰 Presupuesto: ${project.budget_text || 'No especificado'}
📊 Propuestas: ${project.proposals_count}
🌍 Cliente: ${project.client_name || '?'} (${project.client_country || '?'})
⭐ Rating: ${project.client_rating || 'Sin rating'}
✅ Verificado: ${project.client_verified ? 'Sí' : 'No'}
🏷️ Skills: ${(project.skills || []).join(', ')}

---

📝 *PROPUESTA:*
${data.proposal_text}

❓ *PREGUNTAS:*
${data.questions_text || 'Ninguna'}

💶 *Precio sugerido:* €${data.budget_suggested || '?'}
📅 *Plazo:* ${data.delivery_days || '?'} días

---

📌 *Ficha interna:*
Perfil: ${data.internal_notes?.perfil_detectado || '?'}
Dolor: ${data.internal_notes?.dolor_real || '?'}
Por qué yo: ${data.internal_notes?.por_que_yo || '?'}

🔗 ${project.workana_url}`;

return [{
  json: {
    message: msg,
    number: data.config.WHATSAPP_NUMBER,
    evolution_url: data.config.EVOLUTION_URL,
    evolution_instance: data.config.EVOLUTION_INSTANCE,
    auto_sent: isAuto,
    project_title: project.title,
  }
}];
